/**
 * @summary Get per-food meal entries for a kid on a given date, grouped by meal type
 */
export const getGetKidMealLogUrl = (
  kidId: number,
  params: GetKidMealLogParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/kids/${kidId}/meal-log?${stringifiedParams}`
    : `/api/kids/${kidId}/meal-log`;
};

